    41	/** @brief Encode E1AP_SecurityIndication_t (3GPP TS 38.463 9.3.1.23) */
    42	static E1AP_SecurityIndication_t e1_encode_security_indication(const security_indication_t *in)
    43	{
    44	  E1AP_SecurityIndication_t out = {0};
    45	  out.integrityProtectionIndication = in->integrityProtectionIndication;
    46	  out.confidentialityProtectionIndication = in->confidentialityProtectionIndication;
    47	  if (in->integrityProtectionIndication != SECURITY_NOT_NEEDED) {
    48	    asn1cCalloc(out.maximumIPdatarate, ipDataRate);
    49	    ipDataRate->maxIPrate = in->maxIPrate;
    50	  }
    51	  return out;
    52	}
    53	
    54	/** @brief Decode E1AP_SecurityIndication_t (3GPP TS 38.463 9.3.1.23) */
    55	static bool e1_decode_security_indication(security_indication_t *out, const E1AP_SecurityIndication_t *in)
    56	{
    57	  // Confidentiality Protection Indication (M)
    58	  out->confidentialityProtectionIndication = in->confidentialityProtectionIndication;
    59	  // Maximum Integrity Protected Data Rate (Conditional)
    60	  if (in->integrityProtectionIndication != SECURITY_NOT_NEEDED) {
    61	    if (in->maximumIPdatarate)
    62	      out->maxIPrate = in->maximumIPdatarate->maxIPrate;
    63	    else {
    64	      PRINT_ERROR("Received integrityProtectionIndication but maximumIPdatarate IE is missing\n");
    65	      return false;
    66	    }
    67	  }
    68	  return true;
    69	}
