   113	/**
   114	 * @brief Encode E1AP_UP_TNL_Information_t
   115	 */
   116	static E1AP_UP_TNL_Information_t e1_encode_up_tnl_info(const UP_TL_information_t *in)
   117	{
   118	  E1AP_UP_TNL_Information_t out = {0};
   119	  out.present = E1AP_UP_TNL_Information_PR_gTPTunnel;
   120	  asn1cCalloc(out.choice.gTPTunnel, gTPTunnel);
   121	  TRANSPORT_LAYER_ADDRESS_IPv4_TO_BIT_STRING(in->tlAddress, &gTPTunnel->transportLayerAddress);
   122	  INT32_TO_OCTET_STRING(in->teId, &gTPTunnel->gTP_TEID);
   123	  return out;
   124	}
