   126	/**
   127	 * @brief Decode E1AP_UP_TNL_Information_t
   128	 */
   129	static bool e1_decode_up_tnl_info(UP_TL_information_t *out, const E1AP_UP_TNL_Information_t *in)
   130	{
   131	  /* NG UL UP Transport Layer Information (M) (9.3.2.1 of 3GPP TS 38.463) */
   132	  // GTP Tunnel
   133	  struct E1AP_GTPTunnel *gTPTunnel = in->choice.gTPTunnel;
   134	  AssertFatal(gTPTunnel != NULL, "item->nG_UL_UP_TNL_Information.choice.gTPTunnel is a mandatory IE");
   135	  _E1_EQ_CHECK_INT(in->present, E1AP_UP_TNL_Information_PR_gTPTunnel);
   136	  BIT_STRING_TO_TRANSPORT_LAYER_ADDRESS_IPv4(&gTPTunnel->transportLayerAddress, out->tlAddress);
   137	  // GTP-TEID
   138	  OCTET_STRING_TO_INT32(&gTPTunnel->gTP_TEID, out->teId);
   139	  return true;
   140	}
