   142	/** @brief Encode PDCP Configuration IE */
   143	static E1AP_PDCP_Configuration_t e1_encode_pdcp_config(const bearer_context_pdcp_config_t *in)
   144	{
   145	  E1AP_PDCP_Configuration_t out = {0};
   146	  out.pDCP_SN_Size_UL = in->pDCP_SN_Size_UL;
   147	  out.pDCP_SN_Size_DL = in->pDCP_SN_Size_DL;
   148	  asn1cCallocOne(out.discardTimer, in->discardTimer);
   149	  E1AP_T_ReorderingTimer_t *roTimer = calloc_or_fail(1, sizeof(*roTimer));
   150	  out.t_ReorderingTimer = roTimer;
   151	  roTimer->t_Reordering = in->reorderingTimer;
   152	  out.rLC_Mode = in->rLC_Mode;
   153	  if (in->pDCP_Reestablishment) {
   154	    asn1cCallocOne(out.pDCP_Reestablishment, E1AP_PDCP_Reestablishment_true);
   155	  }
   156	  return out;
   157	}
   158	
   159	/** @brief Decode PDCP Configuration IE */
   160	static bool e1_decode_pdcp_config(bearer_context_pdcp_config_t *out, const E1AP_PDCP_Configuration_t *in)
   161	{
   162	  out->pDCP_SN_Size_UL = in->pDCP_SN_Size_UL;
   163	  out->pDCP_SN_Size_DL = in->pDCP_SN_Size_DL;
   164	  if (in->discardTimer) {
   165	    out->discardTimer = *in->discardTimer;
   166	  }
   167	  if (in->t_ReorderingTimer) {
   168	    out->reorderingTimer = in->t_ReorderingTimer->t_Reordering;
   169	  }
   170	  out->rLC_Mode = in->rLC_Mode;
   171	  if (in->pDCP_Reestablishment && *in->pDCP_Reestablishment == E1AP_PDCP_Reestablishment_true)
   172	    out->pDCP_Reestablishment = true;
   173	  return true;
   174	}
