   179	static bool eq_pdcp_config(const bearer_context_pdcp_config_t *a, const bearer_context_pdcp_config_t *b)
   180	{
   181	  _E1_EQ_CHECK_LONG(a->pDCP_SN_Size_UL, b->pDCP_SN_Size_UL);
   182	  _E1_EQ_CHECK_LONG(a->pDCP_SN_Size_DL, b->pDCP_SN_Size_DL);
   183	  _E1_EQ_CHECK_LONG(a->rLC_Mode, b->rLC_Mode);
   184	  _E1_EQ_CHECK_LONG(a->reorderingTimer, b->reorderingTimer);
   185	  _E1_EQ_CHECK_LONG(a->discardTimer, b->discardTimer);
   186	  _E1_EQ_CHECK_INT(a->pDCP_Reestablishment, b->pDCP_Reestablishment);
   187	  return true;
   188	}
